/**
 * User Type Selection Page
 * 
 * Initial onboarding step allowing users to choose between individual
 * or business account types. Routes to appropriate registration forms
 * based on selection.
 */

import React from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { LanguageSelector } from '@/shared/components';
import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';
import '/styles/index.css';

const UserTypeSelection = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { effectiveTheme } = useTheme();

  // Inside component
  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;

  const handleSelection = (userType) => {
    if (userType === 'individual') {
      navigate('/signup-individual');
    } else if (userType === 'business') {
      navigate('/signup-business');
    } else if (userType === 'agent') {
      navigate('/signup-agent');
    }
  };

  return (
    <div className="login-container onboarding-page visible">
      <div className="login-form" style={{ position: 'relative' }}>
        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>

        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          className="login-logo"
        />

        <h2>{t('welcomeToiSmartPay', { ns: 'auth' })}</h2>
        <p className="subtitle">
          {t('chooseAccountType', { ns: 'auth' })}
        </p>

        <div className="selection-cards">
          {/* Individual Option */}
          <div
            className="selection-card blue"
            onClick={() => handleSelection('individual')}
          >
            <div className="selection-card-content">
              <div className="selection-card-icon blue">
                <i className="fa-solid fa-user"></i>
              </div>
              <div className="selection-card-text">
                <h3 className="selection-card-title">{t('individualAccount', { ns: 'auth' })}</h3>
                <p className="selection-card-description">
                  {t('individualAccountDescription', { ns: 'auth' })}
                </p>
              </div>
              <i className="fa-solid fa-chevron-right selection-card-arrow"></i>
            </div>
          </div>

          {/* Business Option */}
          <div
            className="selection-card green"
            onClick={() => handleSelection('business')}
          >
            <div className="selection-card-content">
              <div className="selection-card-icon green">
                <i className="fa-solid fa-briefcase"></i>
              </div>
              <div className="selection-card-text">
                <h3 className="selection-card-title">{t('businessAccount', { ns: 'auth' })}</h3>
                <p className="selection-card-description">
                  {t('businessAccountDescription', { ns: 'auth' })}
                </p>
              </div>
              <i className="fa-solid fa-chevron-right selection-card-arrow"></i>
            </div>
          </div>

          {/* Agent Option */}
          <div
            className="selection-card"
            onClick={() => handleSelection('agent')}
            style={{ marginTop: '16px' }}
          >
            <div className="selection-card-content">
              <div className="selection-card-icon" style={{ backgroundColor: 'var(--text-muted)' }}>
                <i className="fa-solid fa-user-tie"></i>
              </div>
              <div className="selection-card-text">
                <h3 className="selection-card-title">{t('agentAccount', { ns: 'auth', defaultValue: 'Agent Account' })}</h3>
                <p className="selection-card-description">
                  {t('agentAccountDescription', { ns: 'auth', defaultValue: 'For individual agents' })}
                </p>
              </div>
              <i className="fa-solid fa-chevron-right selection-card-arrow"></i>
            </div>
          </div>
        </div>

        <hr />
        <p style={{ textAlign: 'center' }}>{t('alreadyHaveAccount', { ns: 'auth' })}</p>
        <button
          type="button"
          onClick={() => navigate('/login')}
          style={{ width: '100%', backgroundColor: '#23bd00' }}
        >
          {t('signInButton', { ns: 'auth' })}
        </button>
      </div>
    </div>
  );
};

export default UserTypeSelection;
